/**
 * Integration tests for the full analytics pipeline.
 *
 * Tests the complete flow: RouteRequest → AnalyticsRoutes → AnalyticsService → Repositories → Database
 *
 * These tests verify that the entire stack works together end-to-end,
 * using real instances of every layer (no mocks).
 */

import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { OrderRepository } from '../../src/repositories/order.repository.js';
import { UserRepository } from '../../src/repositories/user.repository.js';
import { AnalyticsService } from '../../src/services/analytics.service.js';
import { AnalyticsRoutes } from '../../src/routes/analytics.routes.js';
import type { RouteRequest } from '../../src/routes/types.js';
import type { Order } from '../../src/models/order.js';
import type { User } from '../../src/models/user.js';
import type { DashboardData, OrderMetricSummary, ErrorBody } from '../../src/models/analytics.js';

// ── Helpers ──────────────────────────────────────────────────────────

function req(
  query: Record<string, string | undefined> = {},
  params: Record<string, string | undefined> = {},
): RouteRequest {
  return { query, params };
}

function makeUser(overrides: Partial<User> = {}): User {
  return {
    id: 'u-1',
    name: 'Alice',
    email: 'alice@test.com',
    role: 'member',
    createdAt: new Date('2025-01-10'),
    updatedAt: new Date('2025-01-10'),
    ...overrides,
  };
}

function makeOrder(overrides: Partial<Order> = {}): Order {
  return {
    id: 'o-1',
    userId: 'u-1',
    items: [{ productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 }],
    total: 20,
    status: 'pending',
    createdAt: new Date('2025-03-15T10:00:00Z'),
    updatedAt: new Date('2025-03-15T10:00:00Z'),
    ...overrides,
  };
}

// ── Test suite ───────────────────────────────────────────────────────

describe('Analytics Pipeline Integration', () => {
  let db: Database;
  let orderRepo: OrderRepository;
  let userRepo: UserRepository;
  let service: AnalyticsService;
  let routes: AnalyticsRoutes;

  beforeEach(() => {
    db = new Database();
    orderRepo = new OrderRepository(db);
    userRepo = new UserRepository(db);
    service = new AnalyticsService(orderRepo, userRepo);
    routes = new AnalyticsRoutes(service);
  });

  function seedUsers() {
    userRepo.save(makeUser({ id: 'u-1', name: 'Alice', role: 'admin' }));
    userRepo.save(makeUser({ id: 'u-2', name: 'Bob', email: 'bob@test.com', role: 'member' }));
    userRepo.save(makeUser({ id: 'u-3', name: 'Carol', email: 'carol@test.com', role: 'member' }));
    userRepo.save(makeUser({ id: 'u-4', name: 'Dave', email: 'dave@test.com', role: 'viewer' }));
  }

  function seedOrders() {
    orderRepo.save(makeOrder({
      id: 'o-1',
      userId: 'u-1',
      items: [
        { productId: 'p1', name: 'Widget', quantity: 3, unitPrice: 10 },
        { productId: 'p2', name: 'Gadget', quantity: 1, unitPrice: 50 },
      ],
      total: 80,
      status: 'delivered',
      createdAt: new Date('2025-03-01T08:00:00Z'),
    }));
    orderRepo.save(makeOrder({
      id: 'o-2',
      userId: 'u-2',
      items: [{ productId: 'p1', name: 'Widget', quantity: 5, unitPrice: 10 }],
      total: 50,
      status: 'shipped',
      createdAt: new Date('2025-03-01T14:00:00Z'),
    }));
    orderRepo.save(makeOrder({
      id: 'o-3',
      userId: 'u-1',
      items: [{ productId: 'p3', name: 'Doohickey', quantity: 2, unitPrice: 25 }],
      total: 50,
      status: 'pending',
      createdAt: new Date('2025-03-10T09:00:00Z'),
    }));
    orderRepo.save(makeOrder({
      id: 'o-4',
      userId: 'u-3',
      items: [{ productId: 'p2', name: 'Gadget', quantity: 3, unitPrice: 50 }],
      total: 150,
      status: 'confirmed',
      createdAt: new Date('2025-03-20T16:00:00Z'),
    }));
    orderRepo.save(makeOrder({
      id: 'o-5',
      userId: 'u-2',
      items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
      total: 10,
      status: 'cancelled',
      createdAt: new Date('2025-04-01T12:00:00Z'),
    }));
  }

  // ── Dashboard end-to-end ──────────────────────────────────────────

  describe('GET /analytics/dashboard — full pipeline', () => {
    it('returns complete dashboard with seeded data', () => {
      seedUsers();
      seedOrders();

      const res = routes.getDashboard(req());
      expect(res.status).toBe(200);

      const data = res.data as DashboardData;
      expect(data.orderMetrics.totalOrders).toBe(5);
      expect(data.orderMetrics.totalRevenue).toBe(340);
      expect(data.orderMetrics.averageOrderValue).toBe(68);
      expect(data.orderMetrics.ordersByStatus.delivered).toBe(1);
      expect(data.orderMetrics.ordersByStatus.shipped).toBe(1);
      expect(data.orderMetrics.ordersByStatus.pending).toBe(1);
      expect(data.orderMetrics.ordersByStatus.confirmed).toBe(1);
      expect(data.orderMetrics.ordersByStatus.cancelled).toBe(1);

      expect(data.userMetrics.totalUsers).toBe(4);
      expect(data.userMetrics.usersByRole).toEqual({ admin: 1, member: 2, viewer: 1 });

      expect(data.timeSeries.length).toBeGreaterThan(0);
      expect(data.topProducts.length).toBeGreaterThan(0);
      expect(data.generatedAt).toBeInstanceOf(Date);
    });

    it('returns empty dashboard when no data exists', () => {
      const res = routes.getDashboard(req());
      expect(res.status).toBe(200);

      const data = res.data as DashboardData;
      expect(data.orderMetrics.totalOrders).toBe(0);
      expect(data.orderMetrics.totalRevenue).toBe(0);
      expect(data.userMetrics.totalUsers).toBe(0);
      expect(data.timeSeries).toEqual([]);
      expect(data.topProducts).toEqual([]);
    });

    it('respects granularity parameter through the full stack', () => {
      seedOrders();

      const dayRes = routes.getDashboard(req({ granularity: 'day' }));
      const monthRes = routes.getDashboard(req({ granularity: 'month' }));

      const dayData = dayRes.data as DashboardData;
      const monthData = monthRes.data as DashboardData;

      // Monthly aggregation should produce fewer buckets than daily
      expect(monthData.timeSeries.length).toBeLessThanOrEqual(dayData.timeSeries.length);
    });

    it('respects date range filters through the full stack', () => {
      seedOrders();

      const res = routes.getDashboard(req({
        startDate: '2025-03-05T00:00:00Z',
        endDate: '2025-03-15T23:59:59Z',
      }));

      const data = res.data as DashboardData;
      // Only order o-3 (2025-03-10) falls in this range for time series
      // But orderMetrics/userMetrics/topProducts use all data (only timeSeries is filtered)
      expect(data.timeSeries.length).toBeGreaterThan(0);
      const totalTimeSeriesCount = data.timeSeries.reduce((sum, dp) => sum + dp.count, 0);
      expect(totalTimeSeriesCount).toBe(1); // only o-3
    });

    it('respects topProductsLimit parameter', () => {
      seedOrders();

      const res = routes.getDashboard(req({ topProductsLimit: '1' }));
      const data = res.data as DashboardData;
      expect(data.topProducts.length).toBe(1);
      // Gadget has most revenue: (1*50) + (3*50) = 200
      expect(data.topProducts[0].name).toBe('Gadget');
    });
  });

  // ── Order metrics end-to-end ──────────────────────────────────────

  describe('GET /analytics/orders — full pipeline', () => {
    it('computes correct metrics from database through route', () => {
      seedOrders();

      const res = routes.getOrderMetrics(req());
      expect(res.status).toBe(200);

      const data = res.data as OrderMetricSummary;
      expect(data.totalOrders).toBe(5);
      expect(data.totalRevenue).toBe(340);
      expect(data.averageOrderValue).toBe(68);
    });

    it('reflects repository changes immediately', () => {
      seedOrders();

      const before = routes.getOrderMetrics(req());
      expect((before.data as OrderMetricSummary).totalOrders).toBe(5);

      // Add another order
      orderRepo.save(makeOrder({
        id: 'o-6',
        total: 100,
        status: 'pending',
        createdAt: new Date('2025-04-05T10:00:00Z'),
      }));

      const after = routes.getOrderMetrics(req());
      expect((after.data as OrderMetricSummary).totalOrders).toBe(6);
      expect((after.data as OrderMetricSummary).totalRevenue).toBe(440);
    });
  });

  // ── User metrics end-to-end ───────────────────────────────────────

  describe('GET /analytics/users — full pipeline', () => {
    it('computes correct user breakdown from database through route', () => {
      seedUsers();

      const res = routes.getUserMetrics(req());
      expect(res.status).toBe(200);
      expect(res.data).toEqual({
        totalUsers: 4,
        usersByRole: { admin: 1, member: 2, viewer: 1 },
      });
    });
  });

  // ── Top products end-to-end ───────────────────────────────────────

  describe('GET /analytics/top-products — full pipeline', () => {
    it('ranks products by revenue from real order data', () => {
      seedOrders();

      const res = routes.getTopProducts(req({ limit: '10' }));
      expect(res.status).toBe(200);

      const products = res.data as Array<{ productId: string; name: string; totalRevenue: number; totalQuantity: number }>;
      expect(products.length).toBe(3);

      // Gadget: (1*50) + (3*50) = 200
      expect(products[0].productId).toBe('p2');
      expect(products[0].totalRevenue).toBe(200);
      expect(products[0].totalQuantity).toBe(4);

      // Widget: (3*10) + (5*10) + (1*10) = 90
      expect(products[1].productId).toBe('p1');
      expect(products[1].totalRevenue).toBe(90);
      expect(products[1].totalQuantity).toBe(9);

      // Doohickey: (2*25) = 50
      expect(products[2].productId).toBe('p3');
      expect(products[2].totalRevenue).toBe(50);
      expect(products[2].totalQuantity).toBe(2);
    });

    it('limits results correctly', () => {
      seedOrders();

      const res = routes.getTopProducts(req({ limit: '2' }));
      const products = res.data as Array<{ productId: string }>;
      expect(products.length).toBe(2);
    });
  });

  // ── Time series end-to-end ────────────────────────────────────────

  describe('GET /analytics/time-series — full pipeline', () => {
    it('aggregates orders by day', () => {
      seedOrders();

      const res = routes.getTimeSeries(req({ granularity: 'day' }));
      expect(res.status).toBe(200);

      const points = res.data as Array<{ timestamp: string; count: number; revenue: number }>;
      // Orders span 4 distinct days: Mar 1 (2 orders), Mar 10, Mar 20, Apr 1
      expect(points.length).toBe(4);

      // First bucket (Mar 1): o-1 ($80) + o-2 ($50) = $130
      expect(points[0].count).toBe(2);
      expect(points[0].revenue).toBe(130);
    });

    it('aggregates orders by month', () => {
      seedOrders();

      const res = routes.getTimeSeries(req({ granularity: 'month' }));
      expect(res.status).toBe(200);

      const points = res.data as Array<{ timestamp: string; count: number; revenue: number }>;
      // March: 4 orders ($330), April: 1 order ($10)
      expect(points.length).toBe(2);
      expect(points[0].count).toBe(4);
      expect(points[0].revenue).toBe(330);
      expect(points[1].count).toBe(1);
      expect(points[1].revenue).toBe(10);
    });

    it('filters by date range', () => {
      seedOrders();

      const res = routes.getTimeSeries(req({
        granularity: 'day',
        startDate: '2025-03-10T00:00:00Z',
        endDate: '2025-03-20T23:59:59Z',
      }));
      expect(res.status).toBe(200);

      const points = res.data as Array<{ timestamp: string; count: number }>;
      // Only o-3 (Mar 10) and o-4 (Mar 20) are in range
      const totalCount = points.reduce((sum, p) => sum + p.count, 0);
      expect(totalCount).toBe(2);
    });
  });

  // ── Order metrics for period end-to-end ───────────────────────────

  describe('GET /analytics/orders/period — full pipeline', () => {
    it('filters order metrics to a date range', () => {
      seedOrders();

      const res = routes.getOrderMetricsForPeriod(req({
        startDate: '2025-03-01T00:00:00Z',
        endDate: '2025-03-15T23:59:59Z',
      }));
      expect(res.status).toBe(200);

      const data = res.data as OrderMetricSummary;
      // o-1 (Mar 1, $80), o-2 (Mar 1, $50), o-3 (Mar 10, $50)
      expect(data.totalOrders).toBe(3);
      expect(data.totalRevenue).toBe(180);
      expect(data.averageOrderValue).toBe(60);
    });

    it('returns zeros when no orders fall in range', () => {
      seedOrders();

      const res = routes.getOrderMetricsForPeriod(req({
        startDate: '2024-01-01T00:00:00Z',
        endDate: '2024-12-31T23:59:59Z',
      }));
      expect(res.status).toBe(200);

      const data = res.data as OrderMetricSummary;
      expect(data.totalOrders).toBe(0);
      expect(data.totalRevenue).toBe(0);
    });
  });

  // ── Error scenarios ───────────────────────────────────────────────

  describe('Error handling through the pipeline', () => {
    it('rejects invalid granularity on dashboard', () => {
      const res = routes.getDashboard(req({ granularity: 'century' }));
      expect(res.status).toBe(400);
      expect((res.data as ErrorBody).error).toContain('Invalid granularity');
    });

    it('rejects invalid granularity on time-series', () => {
      const res = routes.getTimeSeries(req({ granularity: 'invalid' }));
      expect(res.status).toBe(400);
      expect((res.data as ErrorBody).error).toContain('Invalid granularity');
    });

    it('rejects invalid startDate on dashboard', () => {
      const res = routes.getDashboard(req({ startDate: 'not-a-date' }));
      expect(res.status).toBe(400);
      expect((res.data as ErrorBody).error).toContain('Invalid startDate');
    });

    it('rejects invalid endDate on time-series', () => {
      const res = routes.getTimeSeries(req({ endDate: 'garbage' }));
      expect(res.status).toBe(400);
      expect((res.data as ErrorBody).error).toContain('Invalid endDate');
    });

    it('rejects invalid topProductsLimit on dashboard', () => {
      const res = routes.getDashboard(req({ topProductsLimit: '-5' }));
      expect(res.status).toBe(400);
      expect((res.data as ErrorBody).error).toContain('Invalid topProductsLimit');
    });

    it('rejects non-numeric topProductsLimit', () => {
      const res = routes.getDashboard(req({ topProductsLimit: 'abc' }));
      expect(res.status).toBe(400);
      expect((res.data as ErrorBody).error).toContain('Invalid topProductsLimit');
    });

    it('rejects invalid limit on top-products', () => {
      const res = routes.getTopProducts(req({ limit: '0' }));
      expect(res.status).toBe(400);
      expect((res.data as ErrorBody).error).toContain('Invalid limit');
    });

    it('requires startDate on orders/period', () => {
      const res = routes.getOrderMetricsForPeriod(req({ endDate: '2025-03-15T00:00:00Z' }));
      expect(res.status).toBe(400);
      expect((res.data as ErrorBody).error).toContain('Missing required parameter: startDate');
    });

    it('requires endDate on orders/period', () => {
      const res = routes.getOrderMetricsForPeriod(req({ startDate: '2025-03-01T00:00:00Z' }));
      expect(res.status).toBe(400);
      expect((res.data as ErrorBody).error).toContain('Missing required parameter: endDate');
    });

    it('rejects invalid startDate on orders/period', () => {
      const res = routes.getOrderMetricsForPeriod(req({
        startDate: 'bad',
        endDate: '2025-03-15T00:00:00Z',
      }));
      expect(res.status).toBe(400);
      expect((res.data as ErrorBody).error).toContain('Invalid date for startDate');
    });

    it('rejects invalid endDate on orders/period', () => {
      const res = routes.getOrderMetricsForPeriod(req({
        startDate: '2025-03-01T00:00:00Z',
        endDate: 'bad',
      }));
      expect(res.status).toBe(400);
      expect((res.data as ErrorBody).error).toContain('Invalid date for endDate');
    });
  });

  // ── Data consistency across endpoints ─────────────────────────────

  describe('Cross-endpoint data consistency', () => {
    it('dashboard order metrics match standalone order metrics endpoint', () => {
      seedOrders();

      const dashRes = routes.getDashboard(req());
      const orderRes = routes.getOrderMetrics(req());

      const dashMetrics = (dashRes.data as DashboardData).orderMetrics;
      const standaloneMetrics = orderRes.data as OrderMetricSummary;

      expect(dashMetrics.totalOrders).toBe(standaloneMetrics.totalOrders);
      expect(dashMetrics.totalRevenue).toBe(standaloneMetrics.totalRevenue);
      expect(dashMetrics.averageOrderValue).toBe(standaloneMetrics.averageOrderValue);
      expect(dashMetrics.ordersByStatus).toEqual(standaloneMetrics.ordersByStatus);
    });

    it('dashboard user metrics match standalone user metrics endpoint', () => {
      seedUsers();

      const dashRes = routes.getDashboard(req());
      const userRes = routes.getUserMetrics(req());

      const dashMetrics = (dashRes.data as DashboardData).userMetrics;
      expect(dashMetrics).toEqual(userRes.data);
    });

    it('dashboard top products match standalone top-products endpoint', () => {
      seedOrders();

      const dashRes = routes.getDashboard(req({ topProductsLimit: '5' }));
      const topRes = routes.getTopProducts(req({ limit: '5' }));

      expect((dashRes.data as DashboardData).topProducts).toEqual(topRes.data);
    });

    it('dashboard time series matches standalone time-series endpoint', () => {
      seedOrders();

      const dashRes = routes.getDashboard(req({ granularity: 'month' }));
      const tsRes = routes.getTimeSeries(req({ granularity: 'month' }));

      expect((dashRes.data as DashboardData).timeSeries).toEqual(tsRes.data);
    });

    it('period metrics are a subset of full metrics', () => {
      seedOrders();

      const fullRes = routes.getOrderMetrics(req());
      const periodRes = routes.getOrderMetricsForPeriod(req({
        startDate: '2025-03-01T00:00:00Z',
        endDate: '2025-03-31T23:59:59Z',
      }));

      const full = fullRes.data as OrderMetricSummary;
      const period = periodRes.data as OrderMetricSummary;

      expect(period.totalOrders).toBeLessThanOrEqual(full.totalOrders);
      expect(period.totalRevenue).toBeLessThanOrEqual(full.totalRevenue);
    });
  });
});

